import fetch from "node-fetch";

// ================= CONFIG =================
const CLAUDE_API_URL = "https://api.anthropic.com/v1/messages";
const MODEL = "claude-3-5-sonnet-20241022";

// 🔴 PASTE YOUR API KEY HERE
const API_KEY = "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";

// ================= CORE FUNCTION =================
async function callClaude(systemPrompt, userPrompt) {
  try {
    const response = await fetch(CLAUDE_API_URL, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-api-key": API_KEY,
        "anthropic-version": "2023-06-01",
      },
      body: JSON.stringify({
        model: MODEL,
        max_tokens: 2000,
        system: systemPrompt,
        messages: [
          {
            role: "user",
            content: userPrompt,
          },
        ],
      }),
    });

    if (!response.ok) {
      const errText = await response.text();
      throw new Error("Claude API Error: " + errText);
    }

    const data = await response.json();

    const text =
      data?.content?.find((c) => c.type === "text")?.text || "";

    if (!text) throw new Error("Empty response from Claude");

    // Clean JSON response
    const clean = text
      .replace(/```json/gi, "")
      .replace(/```/g, "")
      .trim();

    return JSON.parse(clean);
  } catch (err) {
    console.error("Error calling Claude:", err.message);
    throw err;
  }
}

// ================= FEATURE 1 =================
export async function generateRoadmap({
  jobRole,
  jobDescription,
  experienceLevel,
  currentSkills,
}) {
  const systemPrompt = `You are an expert career coach.
Return ONLY valid JSON. No markdown.`;

  const input = jobRole
    ? `Job Role: ${jobRole}`
    : `Job Description: ${jobDescription}`;

  const userPrompt = `
Generate a personalized roadmap:

${input}
Experience Level: ${experienceLevel}
Current Skills: ${
    currentSkills?.length ? currentSkills.join(", ") : "None"
  }

STRICT JSON FORMAT:
{
  "targetRole": "string",
  "totalWeeks": number,
  "phases": [
    {
      "id": number,
      "title": "string",
      "weeks": number,
      "status": "in_progress" | "not_started",
      "topics": ["string"],
      "description": "string"
    }
  ],
  "courses": [
    {
      "id": "string",
      "title": "string",
      "phase": number,
      "phaseLabel": "string",
      "difficulty": "Beginner" | "Intermediate" | "Advanced",
      "hours": number,
      "progress": number,
      "description": "string"
    }
  ],
  "skillGap": [
    {
      "skill": "string",
      "yourLevel": number,
      "required": number,
      "gap": "High" | "Medium" | "Low"
    }
  ],
  "stats": {
    "skillsToMaster": number,
    "estimatedWeeks": number,
    "coursesAvailable": number,
    "completionPercent": number
  }
}

Rules:
- Minimum 4 phases
- Minimum 6 courses
- Keep realistic for ${experienceLevel}
`;

  return callClaude(systemPrompt, userPrompt);
}

// ================= FEATURE 2 =================
export async function analyzeSkillGap({
  targetRole,
  currentSkills,
  experienceLevel,
}) {
  const systemPrompt = `You are a technical skills assessor.
Return ONLY valid JSON.`;

  const userPrompt = `
Analyze skill gap:

Target Role: ${targetRole}
Current Skills: ${currentSkills.join(", ")}
Experience Level: ${experienceLevel}

STRICT JSON:
{
  "skillGap": [
    {
      "skill": "string",
      "yourLevel": number,
      "required": number,
      "gap": "High" | "Medium" | "Low"
    }
  ],
  "recommendations": [
    {
      "title": "string",
      "gap": "High" | "Medium" | "Low",
      "hours": number
    }
  ]
}
`;

  return callClaude(systemPrompt, userPrompt);
}

// ================= TEST RUN =================
(async () => {
  try {
    const roadmap = await generateRoadmap({
      jobRole: "Data Engineer",
      experienceLevel: "Beginner",
      currentSkills: ["Python", "SQL"],
    });

    console.log("ROADMAP RESULT:\n", JSON.stringify(roadmap, null, 2));

    const gap = await analyzeSkillGap({
      targetRole: "Data Engineer",
      experienceLevel: "Beginner",
      currentSkills: ["Python"],
    });

    console.log("\nSKILL GAP RESULT:\n", JSON.stringify(gap, null, 2));
  } catch (err) {
    console.error("FINAL ERROR:", err.message);
  }
})();
